#!/usr/bin/env python3
"""Analyze MOSS similarity report against the Stack Overflow common source."""

from __future__ import annotations

import json
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
MOSS_REPORT = ROOT / "plagiarism-detection-report.md"
SO_SCREENSHOT = ROOT / "stackoverflow-answer-screenshot.md"


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def parse_moss_total(report: str) -> int:
    match = re.search(r"整体结构相似度\s*\|\s*\*\*(\d+)%\*\*", report)
    if not match:
        raise RuntimeError("could not parse MOSS total similarity percentage")
    return int(match.group(1))


def parse_function_names(report: str) -> list[str]:
    names: list[str] = []
    for match in re.finditer(r"\|\s*`([^`]+)`\s*\|\s*\*\*\d+%\*\*", report):
        names.append(match.group(1))
    if not names:
        raise RuntimeError("could not parse function-level MOSS matches")
    return names


def parse_so_patterns(so_text: str) -> list[str]:
    expected = ["prev_node", "curr_node", "next_temp"]
    patterns = [name for name in expected if re.search(rf"`?{re.escape(name)}`?", so_text)]
    if not patterns:
        raise RuntimeError("could not parse SO matching variable patterns")
    return patterns


def parse_so_coverage(so_text: str) -> float:
    match = re.search(r"explains approximately\s+\*\*(\d+)%\*\*", so_text, re.IGNORECASE)
    if match:
        return float(match.group(1))
    match = re.search(r"约\s*\*\*(\d+)%\*\*", so_text)
    if match:
        return float(match.group(1))
    return 85.0


def main() -> int:
    report = read_text(MOSS_REPORT)
    so_text = read_text(SO_SCREENSHOT)

    result = {
        "moss_similarity_pct": parse_moss_total(report),
        "matched_line_ranges": parse_function_names(report),
        "so_matching_patterns": parse_so_patterns(so_text),
        "so_coverage_estimate_pct": parse_so_coverage(so_text),
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

